import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as o}from"./chunks/macos-downloads.DCRwPSpe.js";const s=JSON.parse(`{"title":"Fabric 설치","description":"Fabric을 설치하는 방법에 대한 단계별 가이드입니다.","frontmatter":{"title":"Fabric 설치","description":"Fabric을 설치하는 방법에 대한 단계별 가이드입니다.","authors":["Benonardo","IMB11","modmuss50"],"files":[]},"headers":[],"relativePath":"ko_kr/1.21.8/players/installing-fabric.md","filePath":"versions/1.21.8/translated/ko_kr/players/installing-fabric.md","lastUpdated":1760721669000}`);var c={name:`ko_kr/1.21.8/players/installing-fabric.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Fabric 설치 <a class="header-anchor" href="#h1" aria-label="Permalink to “Fabric 설치”">​</a></h1><p>이 가이드는 오직 공식 Minecraft 런처용 Fabric 설치 방법을 안내합니다. 제3자 런처의 경우, 해당 런처의 문서를 참조하여 주세요.</p><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Fabric 설치기 다운로드 <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Fabric 설치기 다운로드”">​</a></h2><p><a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Fabric 웹사이트</a>에서 Fabric 설치기를 다운로드할 수 있습니다.</p><p>Windows를 사용한다면, Java 설치를 건너뛸 수 있도록 <code>exe</code> 버전 (<code>Windows 용 다운로드</code>) 을 다운로드하세요. 자동으로 공식 런처와 함께 제공되는 Java를 사용합니다.</p><p>macOS 또는 Linux 둥 UNIX 계열의 운영 체제를 사용한다면, <code>.jar</code> 버전을 다운로드 받아야 합니다. 때로는, 다음 단계로 이동하기 전에 Java를 설치해야 할 수도 있습니다.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Fabric 설치기 시작 <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Fabric 설치기 시작”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>설치기를 시작하기 전에, 먼저 모든 Minecraft 인스턴스와 Minecrft 런처를 종료해야 합니다.</p></div><details class="details custom-block"><summary>macOS 사용자들을 위한 정보</summary><p>macOS는, 다운로드 디렉터리에서 <code>.jar</code> 파일을 마우스 오른쪽 버튼으로 클릭하고 <code>열기</code>를 클릭하여 실행해야 할 수 있습니다.</p><p><img src="/assets/players/installing-fabric/macos-downloads.png" alt="Fabric 실행기의 MacOS 컨텍스트 메뉴" loading="lazy"></p><p>정말로 실행할 것인지 묻는다면, 다시 한번 <code>열기</code>를 클릭해주세요.</p></details><p>설치기를 실행하면, 다음과 같은 화면이 나타날 것입니다:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="&quot;Install&quot;을 강조 표시한 Fabric 설치기" loading="lazy"></p><p>Fabric을 설치하려면, 간단히 &quot;Minecraft 버전&quot; 드롭다운 메뉴에서 Fabric을 설치하고자 하는 버전을 선택하고, <code>설치</code>를 클릭하세요.</p><div class="warning custom-block"><p class="custom-block-title">중요!</p><p>&#39;프로필 생성&#39;이 선택되어 있는지 확인하세요!</p></div><h2 id="3-you-re-done" tabindex="-1">3. 이제 끝났습니다! <a class="header-anchor" href="#3-you-re-done" aria-label="Permalink to “3. 이제 끝났습니다!”">​</a></h2><p>설치가 완료되면, Minecraft 런처를 실행하여 왼쪽 아래의 버전 선택 메뉴에서 Fabric을 선택한 후 플레이를 클릭하면 됩니다!</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Fabric 프로필이 선택된 Minecraft 런처" loading="lazy"></p><p>이제 Fabric을 설치했으니, 게임에 모드를 추가할 수 있습니다! <a href="./finding-mods">안전한 모드 찾기</a>에서 자세한 정보를 확인해보세요.</p><p>설치 과정 중 문제가 발생했다면, <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord (영어)</a>의 <code>#player-support</code> 채널에서 도움을 요청할 수 있습니다.</p>`,18)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};